<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bouncing Ball Playground</title>
<style>
  :root {
    --bg: #0f1117;
    --panel: #1a1d27;
    --accent: #5eead4;
    --accent2: #818cf8;
    --text: #e5e7eb;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: var(--bg);
    color: var(--text);
    font-family: system-ui, -apple-system, "Segoe UI", sans-serif;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 18px;
    padding: 24px;
  }
  h1 {
    font-size: 1.2rem;
    font-weight: 600;
    letter-spacing: 0.04em;
    color: var(--accent);
  }
  #sim {
    width: 560px;
    height: 460px;
    max-width: 95vw;
    background: radial-gradient(ellipse at 50% 20%, #1c2030 0%, #12141c 70%);
    border: 1px solid #2a2f40;
    border-radius: 12px;
    box-shadow: 0 8px 40px rgba(0,0,0,0.5), inset 0 0 60px rgba(0,0,0,0.35);
    cursor: crosshair;
    display: block;
  }
  .controls { display: flex; gap: 12px; }
  button {
    background: var(--panel);
    color: var(--text);
    border: 1px solid #2e3345;
    border-radius: 8px;
    padding: 10px 22px;
    font-size: 0.95rem;
    font-weight: 500;
    cursor: pointer;
    transition: transform 0.08s ease, background 0.15s ease, border-color 0.15s ease;
  }
  button:hover { background: #232838; border-color: var(--accent2); }
  button:active { transform: scale(0.96); }
  #drop { border-color: var(--accent); }
  .hint { font-size: 0.8rem; color: #6b7280; }
</style>
</head>
<body>
  <h1>⬤ Bouncing Ball Playground</h1>
  <canvas id="sim"></canvas>
  <div class="controls">
    <button id="drop">Drop Ball</button>
    <button id="play">Pause</button>
    <button id="clear">Clear</button>
  </div>
  <div class="hint">Click the canvas to add a ball at the cursor</div>

<script>
(function () {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');

  // Render at device-pixel resolution but keep logical coords = CSS pixels.
  const cssW = canvas.clientWidth || 560;
  const cssH = canvas.clientHeight || 460;
  const dpr = window.devicePixelRatio || 1;
  canvas.width = Math.round(cssW * dpr);
  canvas.height = Math.round(cssH * dpr);
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

  const W = cssW, H = cssH;

  const GRAVITY = 0.35;        // px per step^2
  const RESTITUTION = 0.82;    // energy kept on bounce
  const WALL_FRICTION = 0.995; // slight drag along walls

  const COLORS = ['#5eead4', '#818cf8', '#f472b6', '#fbbf24', '#34d399', '#60a5fa', '#fb923c'];
  let colorIdx = 0;

  const balls = [];
  let playing = true;

  function addBall(x, y, vx = 0, vy = 0, r) {
    if (r === undefined) r = 8 + ((balls.length * 7) % 13); // 8..20, deterministic variety
    r = Math.max(2, Math.min(r, Math.min(W, H) / 2 - 1));
    const ball = {
      x: Math.min(Math.max(x, r), W - r),
      y: Math.min(Math.max(y, r), H - r),
      vx, vy, r,
      color: COLORS[colorIdx++ % COLORS.length],
    };
    balls.push(ball);
    draw();
    return ball;
  }

  function stepBall(b, dt) {
    b.vy += GRAVITY * dt;
    b.x += b.vx * dt;
    b.y += b.vy * dt;

    // Floor
    if (b.y + b.r > H) {
      b.y = H - b.r;
      if (b.vy > 0) b.vy = -b.vy * RESTITUTION;
      b.vx *= WALL_FRICTION;
    }
    // Ceiling
    if (b.y - b.r < 0) {
      b.y = b.r;
      if (b.vy < 0) b.vy = -b.vy * RESTITUTION;
    }
    // Right wall
    if (b.x + b.r > W) {
      b.x = W - b.r;
      if (b.vx > 0) b.vx = -b.vx * RESTITUTION;
    }
    // Left wall
    if (b.x - b.r < 0) {
      b.x = b.r;
      if (b.vx < 0) b.vx = -b.vx * RESTITUTION;
    }
  }

  function step(dt = 1) {
    // Substep large dt to prevent tunneling through edges.
    const sub = Math.max(1, Math.ceil(Math.abs(dt)));
    const h = dt / sub;
    for (let s = 0; s < sub; s++) {
      for (const b of balls) stepBall(b, h);
    }
    draw();
  }

  function draw() {
    ctx.clearRect(0, 0, W, H);
    for (const b of balls) {
      // soft glow
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r * 1.6, 0, Math.PI * 2);
      const glow = ctx.createRadialGradient(b.x, b.y, b.r * 0.4, b.x, b.y, b.r * 1.6);
      glow.addColorStop(0, b.color + '55');
      glow.addColorStop(1, 'transparent');
      ctx.fillStyle = glow;
      ctx.fill();

      // ball body with a highlight
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      const grad = ctx.createRadialGradient(
        b.x - b.r * 0.35, b.y - b.r * 0.35, b.r * 0.1,
        b.x, b.y, b.r
      );
      grad.addColorStop(0, '#ffffff');
      grad.addColorStop(0.25, b.color);
      grad.addColorStop(1, shade(b.color));
      ctx.fillStyle = grad;
      ctx.fill();
    }
  }

  function shade(hex) {
    const n = parseInt(hex.slice(1), 16);
    const r = (n >> 16) & 255, g = (n >> 8) & 255, b = n & 255;
    return `rgb(${r * 0.35 | 0},${g * 0.35 | 0},${b * 0.35 | 0})`;
  }

  function clear() {
    balls.length = 0;
    draw();
  }

  // --- UI wiring ---
  canvas.addEventListener('click', (e) => {
    const rect = canvas.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (W / rect.width);
    const y = (e.clientY - rect.top) * (H / rect.height);
    addBall(x, y, (x / W - 0.5) * 4, -2);
  });

  document.getElementById('drop').addEventListener('click', () => {
    const x = W * (0.15 + 0.7 * Math.random());
    addBall(x, H * 0.12, (Math.random() - 0.5) * 5, 0);
  });

  const playBtn = document.getElementById('play');
  playBtn.addEventListener('click', () => {
    playing = !playing;
    playBtn.textContent = playing ? 'Pause' : 'Play';
  });

  document.getElementById('clear').addEventListener('click', clear);

  // --- Animation loop ---
  function frame() {
    if (playing) step(1);
    requestAnimationFrame(frame);
  }
  requestAnimationFrame(frame);

  // --- Programmatic API ---
  window.sim = {
    w: W,
    h: H,
    balls: () => balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r })),
    addBall: (x, y, vx = 0, vy = 0, r) => addBall(x, y, vx, vy, r),
    clear,
    step,
  };

  // A couple of starter balls so the canvas isn't empty.
  addBall(W * 0.3, H * 0.2, 2.5, 0);
  addBall(W * 0.65, H * 0.35, -3, -1);
  draw();
})();
</script>
</body>
</html>
